import type { RequestHandler } from 'express';

declare global {
  namespace Express {
    interface Request {
      csp?: { nonce: string };
    }
  }
}

export const cspMiddleware: () => RequestHandler;

/**
 * Security configuration for the application
 * This interface defines the security settings for input validation, CSRF protection, trusted types and CSP
 */
export interface SecurityConfig {
  /**
   * Configuration for the input validation enforcement middleware
   */
  inputValidation: {
    /**
     * Whether input validation is enabled
     */
    enabled: boolean;
    /**
     * Deadline for the validation rules
     * Format: YYYY-MM-DD
     */
    deadline?: string;
    /**
     * Mode of operation for the input validation middleware
     */
    mode?: 'report' | 'warning' | 'block';
    /**
     * List of modules/packages that are allowed without validation
     */
    allowedModules?: string[];
  };
  /**
   * Configuration for CSRF (Cross-Site Request Forgery) protection
   */
  csrf: {
    /**
     * Whether CSRF protection is enabled
     */
    enabled: boolean;
    /**
     * List of paths that should be excluded from CSRF protection
     * These paths can be either exact matches or regex patterns
     */
    ignoredPaths?: Array<RegExp | string>;
  };
  /**
   * Configuration for trusted types
   * Controls which URLs are allowed to be loaded as trusted types
   */
  trustedTypes: {
    /**
     * Regular expression as string that defines trusted URLs
     * Used in createScriptURL policy to validate and allow specific external service URLs
     */
    regex: string | null;
  };
  /**
   * Configuration for CSP (Content Security Policy)
   */
  csp: {
    /**
     * Strict policy configuration for CSP
     */
    strictPolicy?: {
      /**
       * The CSP policy value to be set as Content-Security-Policy header
       */
      value: string;
      /**
       * Backend paths where the strict policy should be applied
       */
      backendPaths: Array<{
        /**
         * Type of path matching: exact, prefix, or regex
         */
        type: 'exact' | 'prefix' | 'regex';
        /**
         * The path value (string for exact/prefix, RegExp for regex)
         */
        value: string | RegExp;
      }>;
    };
  };
}

export interface WebsecConfig {
  get: (key: 'securityConfig') => Promise<SecurityConfig | undefined>;
}

export const websecConfig: WebsecConfig;
